import{_ as t}from"./chunks/14-tui-publish-html.B4-MrVrX.js";import{_ as i,o as a,c as o,a2 as s}from"./chunks/framework.DTa47_fH.js";const b=JSON.parse('{"title":"Publish HTML","description":"","frontmatter":{},"headers":[],"relativePath":"publish-html.md","filePath":"publish-html.md"}'),n={name:"publish-html.md"};function l(r,e,d,h,p,c){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="publish-html" tabindex="-1">Publish HTML <a class="header-anchor" href="#publish-html" aria-label="Permalink to &quot;Publish HTML&quot;">​</a></h1><p>Publish HTML generates a self-contained HTML publication from the latest assessment results. The file is under 2 MB, opens in any browser, works fully offline, and can be emailed directly to the client without any SWAO installation on their side.</p><p>Access from the TUI main menu by pressing <strong>5</strong>.</p><p><img src="'+t+'" alt="SWAO Publish HTML screen"></p><hr><h2 id="publication-options" tabindex="-1">Publication options <a class="header-anchor" href="#publication-options" aria-label="Permalink to &quot;Publication options&quot;">​</a></h2><p>The Publish screen offers two active paths:</p><h3 id="_1-single-html-page-swao-publish-app-id" tabindex="-1">[1] Single HTML page -- <code>swao publish --app &lt;id&gt;</code> <a class="header-anchor" href="#_1-single-html-page-swao-publish-app-id" aria-label="Permalink to &quot;[1] Single HTML page -- `swao publish --app &lt;id&gt;`&quot;">​</a></h3><p>Generates a single <code>.html</code> file containing the complete assessment publication. The file is written to <code>apps/&lt;id&gt;/wsp/publications/&lt;timestamp&gt;-&lt;id&gt;.html</code>.</p><p>The publication includes:</p><ul><li><strong>Executive summary</strong> -- 7R migration verdict, coverage score, and top risks in a format that a senior stakeholder can read in five minutes.</li><li><strong>Compliance pages</strong> -- controls grouped by framework, each with verdict, rationale, and evidence links.</li><li><strong>Risk register</strong> -- interactive table sortable by score, category, and likelihood.</li><li><strong>Signals explorer</strong> -- every signal with full rationale and evidence, searchable by ID or keyword.</li><li><strong>Auditor view</strong> -- signal-level false-positive analysis and rationale coverage metrics.</li><li><strong>Run statistics</strong> -- pass timing, LLM token usage, and cost summary.</li></ul><p><strong>Persona views:</strong> readers can switch between four views in the publication -- Executive, Technical, Auditor, and DPO -- each filtering to the signals and controls most relevant to that role.</p><h3 id="_2-html-editor-swao-publish-edit" tabindex="-1">[2] HTML Editor -- <code>swao publish --edit</code> <a class="header-anchor" href="#_2-html-editor-swao-publish-edit" aria-label="Permalink to &quot;[2] HTML Editor -- `swao publish --edit`&quot;">​</a></h3><p>Opens an interactive browser-based editor where you can customise the publication before saving the final file. Use the editor to:</p><ul><li>Add consultant commentary and engagement context.</li><li>Suppress signals that have been accepted as false positives.</li><li>Adjust the executive summary wording for the specific audience.</li><li>Preview persona views before delivery.</li></ul><p>Changes are saved back to the same workspace-side source -- re-publishing at any time recreates the HTML from the current editor state.</p><hr><h2 id="coming-soon-options" tabindex="-1">Coming-soon options <a class="header-anchor" href="#coming-soon-options" aria-label="Permalink to &quot;Coming-soon options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Planned</th></tr></thead><tbody><tr><td>JSON data export</td><td>Structured export of the publication data model</td></tr><tr><td>HTML Site</td><td>Multi-page static site with search and navigation</td></tr><tr><td>HTML Portal</td><td>Multi-tenant portal with application and portfolio views</td></tr></tbody></table><hr><h2 id="sharing-the-publication" tabindex="-1">Sharing the publication <a class="header-anchor" href="#sharing-the-publication" aria-label="Permalink to &quot;Sharing the publication&quot;">​</a></h2><p>The HTML file is entirely self-contained -- no external dependencies, no server required. You can:</p><ul><li>Email it as an attachment.</li><li>Upload it to a SharePoint or Teams document library.</li><li>Store it in the engagement archive alongside the audit evidence.</li></ul><p>The file name includes a timestamp (<code>&lt;yyyy-mm-dd-HHmm&gt;-&lt;app-id&gt;.html</code>) so multiple publications from different assessment runs are kept as a version history in the publications folder.</p>',24)])])}const g=i(n,[["render",l]]);export{b as __pageData,g as default};
